    global.set("object_time", msg.payload.object_time);
    if (msg.payload.object_lat !== undefined) {
        global.set("object_lat", msg.payload.object_lat);
    }
    if (msg.payload.object_lon !== undefined) {
        global.set("object_lon", msg.payload.object_lon);
    }
}
return msg;

if (msg.topic) {
