    global.set("object_lon_end", msg.payload.object_lon_end);
}

return msg;

if (msg.topic) {
    global.set("object_date_end", msg.payload.object_date_end);
    global.set("object_time_end", msg.payload.object_time_end);
}


return msg;

if (msg.topic) {
    global.set("sample_net_mouth_diameter", msg.payload.sample_net_mouth_diameter);
    global.set("sample_net_length", msg.payload.sample_net_length);
    global.set("sample_net_mesh_size", msg.payload.sample_net_mesh_size);
}
return msg;

if (msg.topic) {
    global.set("sample_filtered_volume", msg.payload.sample_filtered_volume);
    global.set("sample_collected_volume", msg.payload.sample_collected_volume);
    global.set("sample_concentration_factor", msg.payload.sample_concentration_factor);
    global.set("sample_sieve_mesh_size", msg.payload.sample_sieve_mesh_size);
    global.set("sample_depth", msg.payload.sample_depth);
    global.set("sample_comment", msg.payload.sample_comment);
    global.set("sample_depth_min", msg.payload.sample_depth_min);
    global.set("sample_depth_max", msg.payload.sample_depth_max);
}
return msg;

if (msg.topic) {
    global.set("sample_project", msg.payload.sample_project);
    global.set("sample_operator", msg.payload.sample_operator);
    global.set("sample_id", msg.payload.sample_id);
    global.set("sample_gear", msg.payload.sample_gear);
}
return msg;

// 1. Setup Base Variables
const gear = msg.payload.sample_gear;
const now = new Date();
const dateStr = now.toISOString().split('T')[0]; // YYYY-MM-DD
// Time as HHMM (no colons, no seconds) — matches sendUpdate format
const hh = String(now.getUTCHours()).padStart(2, '0');
const mm = String(now.getUTCMinutes()).padStart(2, '0');
const timeStr = hh + mm;

// Helper to get global or fallback
const getG = (key, fallback) => global.get(key) ?? fallback;

// 2. Define the Full Schema Template (All keys)
const allKeys = [
    "object_date", "object_time", "object_lat", "object_lon",
    "object_date_end", "object_time_end", "object_lat_end", "object_lon_end",
    "sample_net_mouth_diameter", "sample_net_length", "sample_net_mesh_size",
    "sample_filtered_volume", "sample_concentration_factor", "sample_sieve_mesh_size",
    "sample_depth", "sample_collected_volume"
];

let updates = {};

// 3. Logic by Gear Type
// All gears use getG() so user-entered values are preserved.
// Defaults are only used when no value exists in globals.
if (gear === "Horizontal Net") {
    updates = {
        object_date: getG("object_date", dateStr),
        object_time: getG("object_time", timeStr),
        object_lat: getG("object_lat", 0),
        object_lon: getG("object_lon", 0),
        object_date_end: getG("object_date_end", getG("object_date", dateStr)),
        object_time_end: getG("object_time_end", getG("object_time", timeStr)),
        object_lat_end: getG("object_lat_end", getG("object_lat", 0)),
        object_lon_end: getG("object_lon_end", getG("object_lon", 0)),
        sample_net_mouth_diameter: getG("sample_net_mouth_diameter", 30),
        sample_net_length: getG("sample_net_length", 120),
        sample_net_mesh_size: getG("sample_net_mesh_size", 20),
        sample_filtered_volume: getG("sample_filtered_volume", 2000),
        sample_concentration_factor: getG("sample_concentration_factor", 1),
        sample_sieve_mesh_size: getG("sample_sieve_mesh_size", 200),
        sample_depth: getG("sample_depth", 1),
        sample_collected_volume: getG("sample_collected_volume", 50)
    };
}
else if (gear === "Vertical Net") {
    updates = {
        object_date: getG("object_date", dateStr),
        object_time: getG("object_time", timeStr),
        object_lat: getG("object_lat", 0),
        object_lon: getG("object_lon", 0),
        sample_net_mouth_diameter: getG("sample_net_mouth_diameter", 30),
        sample_net_length: getG("sample_net_length", 120),
        sample_net_mesh_size: getG("sample_net_mesh_size", 20),
        sample_filtered_volume: getG("sample_filtered_volume", 2000),
        sample_concentration_factor: getG("sample_concentration_factor", 1),
        sample_sieve_mesh_size: getG("sample_sieve_mesh_size", 200),
        sample_depth: getG("sample_depth", 1),
        sample_collected_volume: getG("sample_collected_volume", 50)
    };
}
else if (gear === "Niskin bottle") {
    updates = {
        object_date: getG("object_date", dateStr),
        object_time: getG("object_time", timeStr),
        object_lat: getG("object_lat", 0),
        object_lon: getG("object_lon", 0),
        sample_concentration_factor: getG("sample_concentration_factor", 1),
        sample_sieve_mesh_size: getG("sample_sieve_mesh_size", 200),
        sample_depth: getG("sample_depth", 1),
        sample_collected_volume: getG("sample_collected_volume", 50)
    };
}
else if (gear === "Lab culture") {
    updates = {
        object_date: getG("object_date", dateStr),
        object_time: getG("object_time", timeStr),
        object_lat: getG("object_lat", 0),
        object_lon: getG("object_lon", 0)
    };
}
else if (gear === "Demo / Test") {
    updates = {
        object_date: getG("object_date", dateStr),
        object_time: getG("object_time", timeStr),
        object_lat: getG("object_lat", 48.587440060782704),
        object_lon: getG("object_lon", -3.838189224660975)
    };
}

// 4. Final Processing: Sync to Global & Build Payload
let finalPayload = {};

allKeys.forEach(key => {
    if (updates.hasOwnProperty(key)) {
        // Key is relevant to current gear type - use value (from getG with fallback)
        finalPayload[key] = updates[key];
        global.set(key, updates[key]);
    } else {
        // Key is NOT relevant to current gear type.
        // Send null in payload (disabled fields show empty),
        // but preserve global so user values survive gear switches.
        finalPayload[key] = null;
    }
});

msg.payload = finalPayload;
return msg;

// On récupère le payload
const p = msg.payload;

// On ne procède que si le payload est un objet
if (p && typeof p === 'object') {

    // Liste des paramètres à surveiller et à stocker
    // On boucle sur les clés pour éviter de répéter 20 fois "if(p.x !== undefined)"
    const keys = [
        "acq_id", "acq_nb_frame", "acq_interframe_volume", 
        "acq_imaged_volume", "acq_pumped_volume", "acq_comment",
        "acq_status", "acq_magnification", "acq_tube_lens_reference",
        "acq_objective_lens_reference", "process_pixel_size",
        "calibration_pixel_size", "acq_led_intensity",
        "sensor_width_um", "sensor_height_um", "acq_flowcell_thickness",
        "acq_interframe_flowrate", "acq_stabilization_delay",
        "acq_start_timestamp"
    ];

    keys.forEach(key => {
        if (p[key] !== undefined) {
            global.set(key, p[key]);
        }
    });

    // Patch 8: keep process_pixel in sync with the per-canon process_pixel_size.
    // The form sends process_pixel_size (the factory value for the chosen
    // canon); the imager writes process_pixel into metadata.json and the
    // dashboard's getMagInfo() reads process_pixel. Without this sync the
    // canon selection is silently dropped on the floor. A subsequent
    // calibration (133c27ef…) still wins because it sets process_pixel
    // directly after this point in time.
    if (p.process_pixel_size !== undefined) {
        global.set("process_pixel", Number(p.process_pixel_size));
    }

    // Cas particuliers (noms de propriétés différents entre msg et global)
    if (p.progression !== undefined) global.set("acq_progression", p.progression);
    if (p.duration_left !== undefined) global.set("acq_duration_left", p.duration_left);
}

return msg;

const keys = global.keys(); // Get all global variable keys
msg.payload = {}; // Initialize the payload object

keys.forEach(key => {
    // Ignore keys that start with "$"
    if (!key.startsWith('$')) {
        msg.payload[key] = global.get(key);
    }
});

return msg;

/**
 * Configuration Formatter for EcoTaxa/PlanktoScope
 * Logic: Filters metadata based on the selected 'sample_gear' 
 * and ensures IDs are correctly formatted.
 */

const keys = global.keys();
const gear = global.get('sample_gear') || "Demo / Test";
let rawConfig = {};

// 1. Define "White Lists" for each metadata group
const commonAcq = [
    'acq_comment', 'acq_flowcell_thickness', 'acq_id', 'acq_imaged_volume',
    'acq_instrument', 'acq_interframe_flowrate', 'acq_interframe_volume',
    'acq_magnification', 'acq_nb_frame', 'acq_objective_lens_reference',
    'acq_pumped_volume', 'acq_stabilization_delay', 'acq_tube_lens_reference',
    'acq_volume', 'acq_led_intensity'
];

// Note: Net-specific acquisition meshes
const meshAcq = ['acq_maximum_mesh', 'acq_minimum_mesh'];

const commonSample = [
    'sample_id', 'sample_project', 'sample_operator', 'sample_gear',
    'sample_comment', 'sample_collected_volume', 'sample_concentration_factor',
    'sample_sieve_mesh_size'
];

const commonObject = ['object_date', 'object_time', 'object_lat', 'object_lon'];
const commonProcess = ['process_min_ESD', 'process_pixel_size'];

let allowedKeys = [];

// 2. Select allowed keys based on the Sampling Gear
switch (gear) {
    case "Horizontal Net":
        allowedKeys = [
            ...commonAcq, ...meshAcq, ...commonSample, ...commonProcess, ...commonObject,
            'object_date_end', 'object_time_end', 'object_lat_end', 'object_lon_end',
            'sample_depth_min', 'sample_depth_max', 'sample_filtered_volume',
            'sample_net_length', 'sample_net_mouth_diameter', 'sample_net_mesh_size'
        ];
        break;

    case "Vertical Net":
        allowedKeys = [
            ...commonAcq, ...meshAcq, ...commonSample, ...commonProcess, ...commonObject,
            'acq_status', 'sample_depth_min', 'sample_depth_max', 'sample_filtered_volume',
            'sample_net_length', 'sample_net_mouth_diameter', 'sample_net_mesh_size'
        ];
        break;

    case "Niskin bottle":
        allowedKeys = [
            ...commonAcq, ...meshAcq, ...commonSample, ...commonProcess, ...commonObject,
            'sample_depth_min', 'sample_depth_max', 'sample_net_mesh_size'
        ];
        break;

    case "Lab culture":
        allowedKeys = [...commonAcq, ...meshAcq, ...commonSample, ...commonProcess, ...commonObject];
        break;

    case "Demo / Test":
        // Usually, mesh limits are not required for simple tests
        allowedKeys = [...commonAcq, ...commonSample, ...commonProcess, ...commonObject];
        break;
}

// 3. Extraction & Filtering: only keep keys defined in the allowed list
keys.forEach(key => {
    if (allowedKeys.includes(key)) {
        rawConfig[key] = global.get(key);
    }
});

// 4. EcoTaxa ID Composition (Project_Sample_Acquisition)
// Forced logic for "Demo / Test" project name
const project = (gear === "Demo / Test") ? "TEST_DEBUG" : (rawConfig.sample_project || "");
let sId = String(rawConfig.sample_id || "");
let aId = String(rawConfig.acq_id || "");

// Ensure IDs are fully qualified with prefixes
if (project && !sId.startsWith(project + "_")) {
    sId = project + "_" + sId;
}
if (sId && !aId.startsWith(sId + "_")) {
    aId = sId + "_" + aId;
}

// Update values and sanitize spaces with underscores for filesystem compatibility
rawConfig.sample_project = project;
rawConfig.sample_id = sId.replace(/ /g, "_");
rawConfig.acq_id = aId.replace(/ /g, "_");

// 5. Final Sorting: Group keys alphabetically by prefix (acq_, object_, process_, sample_)
const config = Object.keys(rawConfig)
    .sort()
    .reduce((obj, key) => {
        obj[key] = rawConfig[key];
        return obj;
    }, {});

// 6. Build the Node-RED message
msg.topic = "imager/image";
msg.payload = {
    action: "update_config",
    config: config
};

return msg;

const acq_interframe_volume = msg.payload.acq_interframe_volume
  || global.get("acq_interframe_volume") || 0;
const acq_nb_frame = msg.payload.acq_nb_frame
  || global.get("acq_nb_frame") || 0;
const acq_stabilization_delay = msg.payload.acq_stabilization_delay
  || global.get("acq_stabilization_delay") || 0;
const acq_interframe_flowrate = msg.payload.acq_interframe_flowrate
  || global.get("acq_interframe_flowrate") || 0;

msg.payload = {
    action: "image",
    pump_direction: "FORWARD",
    volume: acq_interframe_volume,
    nb_frame: acq_nb_frame,
    sleep: acq_stabilization_delay,
    flowrate: acq_interframe_flowrate,
};

msg.topic = "imager/image";

return msg;

// Stop the imager acquisition
var stopImager = { topic: "imager/image", payload: { action: "stop" } };

// Also send pump stop command as failsafe
var stopPump = { topic: "actuator/pump", payload: { action: "stop" } };

// Return both messages to be sent
return [[stopImager, stopPump]];

// On vérifie si le message contient les propriétés attendues
// avant de mettre à jour les variables globales.

if (msg.payload) {

    // Si led_status est présent dans le payload, on stocke
    if (msg.payload.led_status !== undefined) {
        global.set("led_status", msg.payload.led_status);
    }

    // Si acq_led_intensity est présent dans le payload, on stocke
    if (msg.payload.acq_led_intensity !== undefined) {
        global.set("acq_led_intensity", msg.payload.acq_led_intensity);
    }
}

return msg;

if (msg.topic) {
    global.set("seg_project_name", msg.payload.dataset.project_name);
    global.set("seg_sample_id", msg.payload.dataset.sample_id);
    global.set("seg_acquisition_id", msg.payload.dataset.acquisition_id);
    global.set("seg_path", msg.payload.dataset.path);
    global.set("process_min_ESD", msg.payload.settings.process_min_ESD);
}
return msg;

const keys = global.keys(); // Get all global variable keys
msg.payload = {}; // Initialize the payload object

keys.forEach(key => {
    // Ignore keys that start with "$"
    if (!key.startsWith('$')) {
        msg.payload[key] = global.get(key);
    }
});

return msg;

// Ensure msg.payload and msg.payload.settings exist
msg.payload = msg.payload || {};

// Read the variable from global context
const process_min_ESD = global.get("process_min_ESD");

// Add it to the payload settings
msg.payload.process_min_ESD = process_min_ESD;
msg.payload.open_dialog = true;

// Return the modified message
return msg;

// Queue Processor - manages the segmentation queue in flow context
//
// Inputs: queue_add, queue_confirmed, queue_segment_request,
//         queue_status_update, queue_cancel, queue_cancel_all, queue_reorder
// Output 0: MQTT command -> segmenter/segment switch
// Output 1: queue_status -> List of Acquisitions (table + modal)
// Output 2: dialog open -> add process_min_ESD -> Dialog

const topic = msg.topic;
const payload = msg.payload;

let queue = flow.get("seg_queue") || [];
let current = flow.get("seg_queue_current") || null;
let results = flow.get("seg_queue_results") || [];
let active = flow.get("seg_queue_active") || false;

function saveState() {
    flow.set("seg_queue", queue);
    flow.set("seg_queue_current", current);
    flow.set("seg_queue_results", results);
    flow.set("seg_queue_active", active);
}

function buildStatusMsg() {
    const completedImages = results.reduce((s, r) => s + (r.image_count || 0), 0);
    const currentImages = current ? (Number(current.item.image_acquired_count) || 0) : 0;
    const pendingImages = queue.reduce((s, q) => s + (Number(q.item.image_acquired_count) || 0), 0);

    return {
        topic: "queue_status",
        payload: {
            active: active,
            current: current ? current.item : null,
            pending: queue.map(q => q.item),
            results: results,
            total_images: completedImages + currentImages + pendingImages,
            completed_images: completedImages
        }
    };
}

function buildMqttMsg(entry) {
    return {
        topic: "segmenter/segment",
        payload: {
            action: "segment",
            path: [entry.item.path],
            settings: {
                force: false,
                recursive: true,
                ecotaxa: true,
                keep: true,
                process_id: 1,
                process_min_ESD: entry.process_min_ESD || 20,
            },
            dataset: {
                project_name: entry.item.project_name,
                sample_id: entry.item.sample_id,
                acquisition_id: entry.item.acquisition_id,
                operator_name: entry.item.operator_name,
                image_acquired_count: entry.item.image_acquired_count,
                path: entry.item.path,
            }
        }
    };
}

function processNext() {
    if (queue.length === 0) {
        active = false;
        current = null;
        saveState();
        return [[null], [buildStatusMsg()], [null]];
    }
    current = queue.shift();
    saveState();
    return [[buildMqttMsg(current)], [buildStatusMsg()], [null]];
}

// --- Handle incoming messages ---

if (topic === "queue_add") {
    // Single item from Dialog confirmation
    const newEntry = {
        item: payload.item,
        process_min_ESD: payload.process_min_ESD || 20
    };

    // Prevent duplicates
    const isDuplicate =
        (current && current.item.path === newEntry.item.path) ||
        queue.some(q => q.item.path === newEntry.item.path);
    if (isDuplicate) {
        return [[null], [buildStatusMsg()], [null]];
    }

    if (!active) {
        queue = [];
        results = [];
        active = true;
        current = newEntry;
        saveState();
        return [[buildMqttMsg(current)], [buildStatusMsg()], [null]];
    } else {
        queue.push(newEntry);
        saveState();
        return [[null], [buildStatusMsg()], [null]];
    }

} else if (topic === "queue_segment_request") {
    // Legacy multi-select request. Open batch dialog.
    const representative = payload.items[0];
    const dialogMsg = {
        topic: "segment_request",
        payload: {
            ...representative,
            is_segmented: false,
            open_dialog: true,
            batch_mode: true,
            batch_count: payload.items.length,
            batch_items: payload.items,
            process_min_ESD: global.get("process_min_ESD") || 20
        }
    };
    return [[null], [null], [dialogMsg]];

} else if (topic === "queue_confirmed") {
    // Legacy batch confirmation
    const items = payload.items || [];
    const confirmedESD = payload.process_min_ESD || 20;
    const toQueue = items.filter(item => !item.is_segmented);
    if (toQueue.length === 0) {
        return [[null], [buildStatusMsg()], [null]];
    }
    for (const item of toQueue) {
        const isDuplicate =
            (current && current.item.path === item.path) ||
            queue.some(q => q.item.path === item.path);
        if (!isDuplicate) {
            queue.push({ item: item, process_min_ESD: confirmedESD });
        }
    }
    if (!active) {
        results = [];
        active = true;
        saveState();
        return processNext();
    }
    saveState();
    return [[null], [buildStatusMsg()], [null]];

} else if (topic === "queue_status_update") {
    const status = (payload.status || "").toLowerCase();

    if (!active || !current) {
        return [[null], [null], [null]];
    }

    if (flow.get("seg_queue_retry_pending") && (status.includes("done") || status.includes("ready"))) {
        flow.set("seg_queue_retry_pending", false);
        return processNext();
    }

    if (status.includes("done")) {
        results.push({ path: current.item.path, acquisition_id: current.item.acquisition_id, status: "done", image_count: Number(current.item.image_acquired_count) || 0 });
        current = null;
        saveState();
        return processNext();

    } else if (status.includes("exception") || status.includes("error")) {
        results.push({ path: current.item.path, acquisition_id: current.item.acquisition_id, status: "error", error: payload.status, image_count: Number(current.item.image_acquired_count) || 0 });
        current = null;
        saveState();
        return processNext();

    } else if (status.includes("interrupted")) {
        const userStop = flow.get("seg_queue_user_stop") || false;
        flow.set("seg_queue_user_stop", false);
        if (userStop) {
            // User-initiated stop: mark as stopped, continue to next in queue
            results.push({ path: current.item.path, acquisition_id: current.item.acquisition_id, status: "stopped", image_count: Number(current.item.image_acquired_count) || 0 });
            current = null;
            saveState();
            return processNext();
        } else {
            // Unexpected interruption: halt queue
            results.push({ path: current.item.path, acquisition_id: current.item.acquisition_id, status: "error", error: "Interrupted", image_count: Number(current.item.image_acquired_count) || 0 });
            active = false;
            current = null;
            queue = [];
            saveState();
            return [[null], [buildStatusMsg()], [null]];
        }

    } else if (status.includes("dead")) {
        results.push({ path: current.item.path, acquisition_id: current.item.acquisition_id, status: "error", error: "Segmenter process died", image_count: Number(current.item.image_acquired_count) || 0 });
        active = false;
        current = null;
        queue = [];
        saveState();
        return [[null], [buildStatusMsg()], [null]];

    } else if (status.includes("busy")) {
        queue.unshift(current);
        current = null;
        flow.set("seg_queue_retry_pending", true);
        saveState();
        return [[null], [buildStatusMsg()], [null]];
    }

    return [[null], [buildStatusMsg()], [null]];

} else if (topic === "queue_reorder") {
    const newOrder = payload.order || [];
    const reordered = [];
    for (const path of newOrder) {
        const entry = queue.find(q => q.item.path === path);
        if (entry) reordered.push(entry);
    }
    queue = reordered;
    saveState();
    return [[null], [buildStatusMsg()], [null]];

} else if (topic === "queue_cancel") {
    queue = queue.filter(q => q.item.path !== payload.path);
    saveState();
    return [[null], [buildStatusMsg()], [null]];

} else if (topic === "queue_cancel_all") {
    queue = [];
    saveState();
    return [[null], [buildStatusMsg()], [null]];

} else if (topic === "queue_stop_segmentation") {
    if (!active || !current) {
        return [[null], [buildStatusMsg()], [null]];
    }
    flow.set("seg_queue_user_stop", true);
    return [[{topic: "segmenter/segment", payload: {action: "stop"}}], [buildStatusMsg()], [null]];
}

return [[null], [null], [null]];

// Queue Status Handler
// Receives status/segmenter MQTT messages, forwards to Queue Processor
// when queue is active. Also sends progress to the table.

const active = flow.get("seg_queue_active") || false;
const current = flow.get("seg_queue_current") || null;
const retryPending = flow.get("seg_queue_retry_pending") || false;

if (!active && !current && !retryPending) {
    return null;
}

const queueMsg = {
    topic: "queue_status_update",
    payload: msg.payload
};

const tableMsg = {
    topic: "queue_progress",
    payload: {
        ...msg.payload,
        current_path: current ? current.item.path : null
    }
};

return [[queueMsg], [tableMsg]];

// Queue Status Refresh - sends current queue state to the table on page load

const queue = flow.get("seg_queue") || [];
const current = flow.get("seg_queue_current") || null;
const results = flow.get("seg_queue_results") || [];
const active = flow.get("seg_queue_active") || false;

const completedImages = results.reduce((s, r) => s + (r.image_count || 0), 0);
const currentImages = current ? (Number(current.item.image_acquired_count) || 0) : 0;
const pendingImages = queue.reduce((s, q) => s + (Number(q.item.image_acquired_count) || 0), 0);

msg = {
    topic: "queue_status",
    payload: {
        active: active,
        current: current ? current.item : null,
        pending: queue.map(q => q.item),
        results: results,
        total_images: completedImages + currentImages + pendingImages,
        completed_images: completedImages
    }
};
return msg;

msg.payload = msg.payload.map(item => {
    const acq = (item.acquisition_id || '').replace(/ /g, '_');
    const sample = (item.sample_id || 'unknown_sample').replace(/ /g, '_');
    item.export = '/ps/data/browse/api/raw/export/ecotaxa/ecotaxa_' + acq + '.zip';
    return item;
});
return msg;

// Find the TSV file in the directory
if (msg.payload.path) {

    const currentPath = msg.payload.path;
    const cleanPath = currentPath.endsWith('/') ? currentPath.slice(0, -1) : currentPath;

    // Save the actual directory path relative to objects root for image URL construction
    const objRoot = "/home/pi/data/objects/";
    msg.tsvDir = cleanPath.startsWith(objRoot) ? cleanPath.slice(objRoot.length) : cleanPath;

    // Find any Ecotaxa/ecotaxa TSV in the directory
    try {
        const files = fs.readdirSync(cleanPath);
        const tsvFile = files.find(f => f.toLowerCase().startsWith('ecotaxa_') && f.endsWith('.tsv'));
        if (tsvFile) {
            msg.payload.path = cleanPath + '/' + tsvFile;
        } else {
            node.warn('No ecotaxa TSV found in ' + cleanPath);
            return null;
        }
    } catch(e) {
        node.error('Cannot read directory: ' + e.message);
        return null;
    }
}

return msg;

const MAX_LINES = 5001;
const MAX_SIZE = 10 * 1024 * 1024;

const filePath = msg.payload.path || msg.filename;
if (!filePath) { return null; }

try {
    const stats = fs.statSync(filePath);
    if (stats.size > MAX_SIZE) {
        const fd = fs.openSync(filePath, "r");
        const buf = Buffer.alloc(Math.min(stats.size, 2 * 1024 * 1024));
        const bytesRead = fs.readSync(fd, buf, 0, buf.length, 0);
        fs.closeSync(fd);
        const partial = buf.toString("utf8", 0, bytesRead);
        const lines = partial.split("\n");
        msg.payload = lines.slice(0, MAX_LINES).join("\n");
        node.warn("Large TSV (" + Math.round(stats.size/1024/1024) + "MB) - limited to " + MAX_LINES + " lines");
        msg.path = msg.payload.path;
    } else {
        msg.payload = fs.readFileSync(filePath, "utf8");
        msg.path = msg.payload.path;
    }
    return msg;
} catch(e) {
    node.error("File read error: " + e.message, msg);
    return null;
}

// This function clears the plot by sending an empty data array.
// Any template using msg.payload.data will immediately purge the plot.

msg.payload = {
    data: []
};

return msg;

// VALIDATION METADATA - extract sample/acquisition/process metadata
// + frame count from TSV. Subset of the AUDIT function focused on metadata only.

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const ix = (c) => headers.indexOf(c);

let firstRow = null;
for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim().startsWith("[")) { firstRow = lines[i].split("\t"); break; }
}
if (!firstRow) return null;

const col = (name) => {
  const i = headers.indexOf(name);
  return i >= 0 ? (firstRow[i] || "") : "";
};

const sampleDate = (col("object_date") + " " + col("object_time")).trim();

const meta = {
  //sample
  sample_project:        col("sample_project"),
  sample_id:             col("sample_id"),

  sample_operator:       col("sample_operator"),
  sample_gear:           col("sample_gear"),

  sample_date:           col("object_date"),
  sample_time:           col("object_time"),

  object_lat:            col("object_lat"),
  object_lon:            col("object_lon"),

  sample_date_end:           col("object_date_end"),
  sample_time_end:           col("object_time_end"),

  object_lat_end:            col("object_lat_end"),
  object_lon_end:            col("object_lon_end"),

  sample_depth_min: col("sample_depth_min"),
  sample_depth_max: col("sample_depth_max"),

  sample_collected_volume: col("sample_collected_volume"),
  sample_filtered_volume: col("sample_filtered_volume"),

  sample_net_mouth_diameter: col("sample_net_mouth_diameter"),
  sample_net_length: col("sample_net_length"),
  sample_net_mesh_size: col("sample_net_mesh_size"),

  sample_sieve_mesh_size: col("sample_sieve_mesh_size"),
  sample_concentration_factor: col("sample_concentration_factor"),

  sample_comment: col("sample_comment"),

  //acquisition
  acq_id: col("acq_id"),
  acq_nb_frame: col("acq_nb_frame"),

  acq_interframe_volume: col("acq_interframe_volume"),
  acq_interframe_flowrate: col("acq_interframe_flowrate"),
  acq_stabilization_delay: col("acq_stabilization_delay"),
  acq_imaged_volume: col("acq_imaged_volume"),
  acq_pumped_volume: col("acq_pumped_volume"),


  acq_flowcell_thickness: col("acq_flowcell_thickness"),


  acq_uuid:              col("acq_uuid"),

  acq_camera_iso:           col("acq_camera_iso"),
  acq_camera_shutter_speed: col("acq_camera_shutter_speed"),
  acq_led_intensity: col("acq_led_intensity"),

  acq_camera_resolution: col("acq_camera_resolution"),
  acq_tube_lens_reference: col("acq_tube_lens_reference"),
  acq_objective_lens_reference: col("acq_objective_lens_reference"),
  acq_magnification: col("acq_magnification"),

  acq_comment: col("acq_comment"),

  //process
  process_min_ESD: col("process_min_ESD"),
  process_pixel:            col("process_pixel"),
  process_datetime: col("process_datetime"),
  acq_instrument_serial_number: col("acq_instrument_serial_number"),
};


// Frame count + total object count
const cFile = ix("img_file_name");
const framePrefixRe = /^(.+?)_\d+\.(jpe?g|png)$/i;
const frames = new Set();
let totalObjects = 0;
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  totalObjects++;
  if (cFile >= 0) {
    const r = l.split("\t");
    const file = r[cFile];
    if (file) {
      const m = file.match(framePrefixRe);
      frames.add(m ? m[1] : file);
    }
  }
}

msg.payload = {
  meta,
  summary: { totalObjects, nFrames: frames.size }
};
return msg;

// --- GALLERY Function Node (Robust Version) ---

// 1. Handle Clear Signals
if (msg.clear === true || (msg.payload && msg.payload.clear === true)) {
    msg.payload = { data: [], meta: { resolution: 1 }, keys: [] };
    return msg;
}

// 2. Validate Incoming Payload
if (!msg.payload || typeof msg.payload !== 'string') {
    node.error("Invalid Payload: Expected a TSV string.");
    return null;
}

// Split by line and filter out empty lines
const lines = msg.payload.split(/\r?\n/).filter(l => l.trim() !== '');

if (lines.length < 2) {
    msg.payload = { data: [], meta: { resolution: 1 }, keys: [] };
    return msg;
}

// 3. Parse Headers
// We use a regex to split by tabs, handling potential empty trailing tabs
const headers = lines[0].split('\t').map(h => h.trim().replace(/^"|"$/g, ''));

/**
 * Utility function to retrieve a value by column name
 * Includes a check to prevent index shifting
 */
const get = (row, key) => {
    const idx = headers.indexOf(key);
    if (idx === -1) return null;

    let val = row[idx];
    if (val === undefined) return null;

    return val.trim().replace(/^"|"$/g, '');
};

// 4. Extract Metadata
let firstRowData = lines[1].split('\t');
const meta = {
    sample_id: get(firstRowData, 'sample_id') || "N/A",
    project: get(firstRowData, 'sample_project') || "N/A",
    acq_id: get(firstRowData, 'acq_id') || "N/A",
    resolution: parseFloat(get(firstRowData, 'process_pixel_size')) || 1.0
};

// 5. Select Numeric Keys
const usefulKeys = [
    "object_area", "object_width", "object_height",
    "object_equivalent_diameter", "object_major", "object_minor",
    "object_MeanHue", "object_elongation", "object_blur_laplacian"
];

const data = [];

// 6. Process Object Rows
for (let i = 1; i < lines.length; i++) {
    const rowLine = lines[i];
    if (rowLine.startsWith('[')) continue;

    const row = rowLine.split('\t');

    // Safety check: if row has fewer columns than header, it's malformed
    if (row.length < headers.length - 2) continue;

    // Use object_id as primary identifier
    const objectId = get(row, 'object_id');
    if (!objectId) continue;

    // --- CONSTRUCT IMAGE URL ---
    let imageUrl = "";
    if (msg.tsvDir) {
        imageUrl = `/api/files/objects/${msg.tsvDir}/${objectId}.jpg`;
    } else {
        imageUrl = `/api/files/objects/${get(row, 'object_date')}/${get(row, 'sample_id')}/${get(row, 'acq_id')}/${objectId}`;
    }

    const item = {
        id: objectId,
        url: imageUrl
    };

    // Parse numeric values
    usefulKeys.forEach(k => {
        let v = parseFloat(get(row, k));
        item[k] = isNaN(v) ? 0 : v;
    });

    data.push(item);
}

// 7. Limit rows
const MAX_ROWS = 5000;
if (data.length > MAX_ROWS) data.length = MAX_ROWS;

// 8. Final Output + Debug mapping check
msg.payload = {
    data: data,
    keys: usefulKeys,
    meta: meta,
    debug: {
        rowCount: data.length,
        firstUrl: data.length > 0 ? data[0].url : "no data",
        // This helps you check if the mapping is correct
        header_check: {
            object_id_index: headers.indexOf('object_id'),
            sample_id_index: headers.indexOf('sample_id'),
            total_headers: headers.length
        }
    }
};

return msg;

// SHARPNESS — focus statistics from object_blur_laplacian column.
// Emits { total, median, p10, p90, sharpPct, blurryPct }.

const SHARP_LAPLACIAN_MIN  = 70;  // values >= this are "in focus"
const BLURRY_LAPLACIAN_MAX = 60;   // values <  this are "blurry"

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = { total: 0, median: 0, p10: 0, p90: 0, sharpPct: 0, blurryPct: 0, _empty: true };
  return msg;
}

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const cBlur = headers.indexOf("object_blur_laplacian");
if (cBlur < 0) return null;

const blurs = [];
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  const v = parseFloat(l.split("\t")[cBlur]);
  if (Number.isFinite(v)) blurs.push(v);
}
blurs.sort((a, b) => a - b);

const q = (arr, p) => arr.length ? arr[Math.floor(arr.length * p)] : 0;
const total = blurs.length;
const sharp  = blurs.filter(v => v >= SHARP_LAPLACIAN_MIN).length;
const blurry = blurs.filter(v => v <  BLURRY_LAPLACIAN_MAX).length;

msg.payload = {
  total,
  median:    q(blurs, 0.5),
  p10:       q(blurs, 0.1),
  p90:       q(blurs, 0.9),
  sharpPct:  total ? 100 * sharp  / total : 0,
  blurryPct: total ? 100 * blurry / total : 0
};
return msg;

// STUCK — per-frame spatial-bin stuck detection.
// Mirrors the AUDIT function's logic but emits only the stuck-related fields.
//
// A bin is "stuck" if it contains a detection in >= MIN_STUCK_FRAMES unique
// frames. Each detection in such a bin is then tagged stuck.
//
// Emits { total, stuckCount, stuckPct, stuckPoints: [{x,y}...],
//         binPx, minStuckFrames, across, along }.

const BIN_PX = 60;
const MIN_STUCK_FRAMES = 8;
const ACROSS = 3040;   // sensor short axis (after rotation, x dimension on UI)
const ALONG  = 4056;   // sensor long axis  (y dimension on UI)

const empty = () => ({
  total: 0, stuckCount: 0, stuckPct: 0, stuckPoints: [],
  binPx: BIN_PX, minStuckFrames: MIN_STUCK_FRAMES, across: ACROSS, along: ALONG,
  _empty: true
});

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = empty();
  return msg;
}

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const cX = headers.indexOf("object_x");
const cY = headers.indexOf("object_y");
const cFile = headers.indexOf("img_file_name");
if (cX < 0 || cY < 0) return null;

const bw = Math.ceil(ACROSS / BIN_PX);
const bh = Math.ceil(ALONG / BIN_PX);
const binFrames = new Array(bw * bh);
const framePrefixRe = /^(.+?)_\d+\.(jpe?g|png)$/i;

const objs = [];
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  const r = l.split("\t");
  const x = parseFloat(r[cX]);
  const y = parseFloat(r[cY]);
  if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
  const file = cFile >= 0 ? r[cFile] : null;
  let frame = null;
  if (file) {
    const m = file.match(framePrefixRe);
    frame = m ? m[1] : file;
  }
  // Match AUDIT's binning: heatmap x = object_y, heatmap y = object_x
  const bxi = Math.min(bw - 1, Math.max(0, Math.floor(y / BIN_PX)));
  const byi = Math.min(bh - 1, Math.max(0, Math.floor(x / BIN_PX)));
  const bin = byi * bw + bxi;
  objs.push({ x, y, frame, bin });
  if (frame != null) {
    const s = binFrames[bin] || (binFrames[bin] = new Set());
    s.add(frame);
  }
}

let stuckCount = 0;
const stuckPoints = [];
for (const o of objs) {
  const fs = binFrames[o.bin];
  if (fs && fs.size >= MIN_STUCK_FRAMES) {
    stuckCount++;
    stuckPoints.push({ x: o.x, y: o.y });
  }
}

msg.payload = {
  total: objs.length,
  stuckCount,
  stuckPct: objs.length ? 100 * stuckCount / objs.length : 0,
  stuckPoints,
  binPx: BIN_PX,
  minStuckFrames: MIN_STUCK_FRAMES,
  across: ACROSS, along: ALONG
};
return msg;

// CONCENTRATION — objects per frame from img_file_name + row count.
// Emits { totalObjects, nFrames, perFrame }.

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = { totalObjects: 0, nFrames: 0, perFrame: 0, _empty: true };
  return msg;
}

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const cFile = headers.indexOf("img_file_name");

const framePrefixRe = /^(.+?)_\d+\.(jpe?g|png)$/i;
const frames = new Set();
let total = 0;
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  total++;
  if (cFile >= 0) {
    const r = l.split("\t");
    const f = r[cFile];
    if (f) {
      const m = f.match(framePrefixRe);
      frames.add(m ? m[1] : f);
    }
  }
}

const nFrames = frames.size;
msg.payload = {
  totalObjects: total,
  nFrames,
  perFrame: nFrames ? total / nFrames : 0
};
return msg;

// HOMOGENEITY — per-frame object counts → coefficient of variation (std/mean).
// Frames are sorted chronologically by their timestamp prefix (filename).
// Emits { totalObjects, nFrames, perFrameCounts, mean, std, cv (percent) }.

const empty = () => ({ totalObjects: 0, nFrames: 0, perFrameCounts: [],
                       mean: 0, std: 0, cv: 0, _empty: true });

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = empty();
  return msg;
}

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const cFile = headers.indexOf("img_file_name");
if (cFile < 0) return null;

const framePrefixRe = /^(.+?)_\d+\.(jpe?g|png)$/i;
const counts = new Map();
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  const r = l.split("\t");
  const f = r[cFile];
  if (!f) continue;
  const m = f.match(framePrefixRe);
  const frame = m ? m[1] : f;
  counts.set(frame, (counts.get(frame) || 0) + 1);
}

const orderedFrames = Array.from(counts.keys()).sort();
const perFrameCounts = orderedFrames.map(f => counts.get(f));
const n = perFrameCounts.length;
const total = perFrameCounts.reduce((a, b) => a + b, 0);
const mean = n ? total / n : 0;
const variance = n ? perFrameCounts.reduce((s, c) => s + (c - mean) ** 2, 0) / n : 0;
const std = Math.sqrt(variance);

msg.payload = {
  totalObjects: total,
  nFrames: n,
  perFrameCounts,
  mean,
  std,
  cv: mean ? 100 * std / mean : 0
};
return msg;

// SPATIAL — left / center / right distribution across the flowcell width.
// object_y is the across-flowcell axis (0 .. ACROSS).
// Emits { total, points: [{x,y}...], leftPct, centerPct, rightPct, across, along }.

const ACROSS = 3040;
const ALONG  = 4056;

const empty = () => ({
  total: 0, points: [], leftPct: 0, centerPct: 0, rightPct: 0,
  across: ACROSS, along: ALONG, _empty: true
});

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = empty();
  return msg;
}

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const cX = headers.indexOf("object_x");
const cY = headers.indexOf("object_y");
if (cX < 0 || cY < 0) return null;

const t1 = ACROSS / 3, t2 = 2 * ACROSS / 3;
let left = 0, center = 0, right = 0;
const points = [];
for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  const r = l.split("\t");
  const x = parseFloat(r[cX]);
  const y = parseFloat(r[cY]);
  if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
  if (y < t1)      left++;
  else if (y < t2) center++;
  else             right++;
  points.push({ x, y });
}

const total = left + center + right;
msg.payload = {
  total,
  points,
  leftPct:   total ? 100 * left   / total : 0,
  centerPct: total ? 100 * center / total : 0,
  rightPct:  total ? 100 * right  / total : 0,
  across: ACROSS,
  along: ALONG
};
return msg;

// LOAD flat_color — reads the flat_color.jpg for the current acquisition
// from /home/pi/data/clean/<tsvDir>/ and emits it as a base64 data URL.
// Fans out to panels 1, 2, 3, 4. msg.tsvDir was set by 'Get tsv path'
// upstream and preserved through 'Size-safe file read'.

const CLEAN_ROOT = "/home/pi/data/clean/";

if (msg.payload && Array.isArray(msg.payload.data) && msg.payload.data.length === 0) {
  msg.payload = { flatColor: null, _empty: true };
  return msg;
}

if (!msg.tsvDir) {
  msg.payload = { flatColor: null };
  return msg;
}

const cleanDir = CLEAN_ROOT + String(msg.tsvDir).replace(/^\/+/, "").replace(/\/+$/, "");
try {
  const buf = fs.readFileSync(cleanDir + "/flat_color.jpg");
  msg.payload = { flatColor: "data:image/jpeg;base64," + buf.toString("base64") };
