// Build paths for segmentation artifacts to delete
const item = msg.payload;
const acqPath = item.path; // Original: "/home/pi/data/objects/..."
const project = item.project_name || "";
const acqId = item.acquisition_id || "";

// 1. Path for done.txt: Swap "/objects/" with "/img/"
const doneTxt = acqPath.replace("/objects/", "/img/") + "/done.txt";

// 2. Path for EcoTaxa zip
// Note: acqId already contains the project name in your payload
const zipFile = "/home/pi/data/export/ecotaxa/ecotaxa_" + acqId + ".zip";

// 3. Path for clean directory
