// AUDIT (Segmentation Audit) - TSV -> rich per-object records + summary + thumbnails
//
// Emits:
//   msg.payload = {
//     meta: { sample_id, project, acq_id },
//     summary: { totalObjects, nFrames, stuckCount, stuckPct, medianBlur, medianESD },
//     objects: [{ x, y, bx, by, w, h, esd, blur, frame, stuck, stuckRun, thumb }]
//   }
//
// Stuck detection uses per-frame spatial binning:
//   - frame = timestamp prefix parsed from img_file_name (YYYY-MM-DD_HH-MM-SS-microsec)
//   - bin each detection into a 60-px grid
//   - bin is "stuck" if it has a detection in >= MIN_STUCK_FRAMES unique frames
//   - stuckRun = unique-frame count for that bin

const MAX_THUMBS = 500;
const OBJ_ROOT = "/home/pi/data/objects/";
const CLEAN_ROOT = "/home/pi/data/clean/";
const BIN_PX = 60;
const MIN_STUCK_FRAMES = 8;

const lines = msg.payload.toString().trim().split(/\r?\n/);
if (lines.length < 2) return null;

const headers = lines[0].split("\t");
const ix = (c) => headers.indexOf(c);
const cX = ix("object_x"), cY = ix("object_y");
const cBx = ix("object_bx"), cBy = ix("object_by");
const cW = ix("object_width"), cH = ix("object_height");
const cESD = ix("object_equivalent_diameter");
const cBlur = ix("object_blur_laplacian");
const cFile = ix("img_file_name");
const cContour = ix("object_contour");
const cSample = ix("sample_id"), cProj = ix("sample_project"), cAcq = ix("acq_id");

let firstRow = null;
for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim().startsWith("[")) { firstRow = lines[i].split("\t"); break; }
}
if (!firstRow) return null;

// Pull every column the Metadata card renders. Each cell is string-from-TSV,
// so undefined/empty stay empty and the template's v-if hides the row.
const col = (name) => {
  const i = headers.indexOf(name);
  return i >= 0 ? (firstRow[i] || "") : "";
};
const sampleDate = (col("object_date") + " " + col("object_time")).trim();
const processOps = [];
for (const k of [
  "process_1st_operation","process_2nd_operation","process_3rd_operation",
  "process_4th_operation","process_5th_operation","process_6th_operation",
  "process_7th_operation"
]) {
  const v = col(k);
  if (v) processOps.push(v);
}

const meta = {
  sample_id:        col("sample_id"),
  project:          col("sample_project"),
  acq_id:           col("acq_id"),
  operator:         col("sample_operator"),
  sampling_gear:    col("sample_gear"),
  lat:              col("object_lat"),
  lon:              col("object_lon"),
  sample_date:      sampleDate,
  volume_pumped:    col("acq_pumped_volume"),
  acq_comment:      col("acq_comment"),
  instrument:       col("acq_camera_resolution") ? ("PlanktoScope · " + col("acq_camera_resolution")) : "",
  instrument_serial: col("acq_uuid"),
  iso:              col("acq_camera_iso"),
  shutter_speed:    col("acq_camera_shutter_speed"),
  pixel_size:       col("process_pixel"),
  process_date:     col("process_datetime"),
};
// Map process_Nth_operation TSV cells into op1..op7 for the template.
processOps.forEach((v, i) => { meta["op" + (i + 1)] = v; });

// --- First pass: parse rows, extract frame IDs, populate bins ---
const objs = [];
const framePrefixRe = /^(.+?)_\d+\.(jpe?g|png)$/i;

const ACROSS = 3040, ALONG = 4056;
// Preview renders the IMX477R capture in portrait (rotated 90° from the raw
// landscape 4056×3040). Match that on the audit panels so the flat field and
// contour map are directly comparable: heatmap x = object_y (across = 3040),
// heatmap y = object_x (along = 4056).
const bw = Math.ceil(ACROSS / BIN_PX);
const bh = Math.ceil(ALONG / BIN_PX);

// per-bin set of unique frame IDs
const binFrames = new Array(bw * bh);

const binOfXY = (x, y) => {
  const bxi = Math.min(bw - 1, Math.max(0, Math.floor(y / BIN_PX)));
  const byi = Math.min(bh - 1, Math.max(0, Math.floor(x / BIN_PX)));
  return byi * bw + bxi;
};

for (let i = 1; i < lines.length; i++) {
  const l = lines[i];
  if (!l || l.trim().startsWith("[")) continue;
  const r = l.split("\t");
  const x = parseFloat(r[cX]);
  const y = parseFloat(r[cY]);
  if (!Number.isFinite(x) || !Number.isFinite(y)) continue;

  const file = cFile >= 0 ? r[cFile] : null;
  let frame = null;
  if (file) {
    const m = file.match(framePrefixRe);
    frame = m ? m[1] : file;
  }

  const o = {
    x, y,
    bx: cBx >= 0 ? parseFloat(r[cBx]) : null,
    by: cBy >= 0 ? parseFloat(r[cBy]) : null,
    w:  cW  >= 0 ? parseFloat(r[cW])  : null,
    h:  cH  >= 0 ? parseFloat(r[cH])  : null,
    esd:  cESD  >= 0 ? parseFloat(r[cESD])  : null,
    blur: cBlur >= 0 ? parseFloat(r[cBlur]) : null,
    frame,
    file,
    stuck: false,
    stuckRun: 0,
    thumb: null,
    contour: null,
    _bin: 0
  };
  if (cContour >= 0) {
    const raw = r[cContour];
    if (raw && raw[0] === "[") {
      try { o.contour = JSON.parse(raw); } catch (_) { o.contour = null; }
    }
  }
  o._bin = binOfXY(x, y);
  objs.push(o);

  if (frame != null) {
    const s = binFrames[o._bin] || (binFrames[o._bin] = new Set());
    s.add(frame);
  }
}

// --- Build frame index + summary ---
const allFrames = new Set();
for (const o of objs) if (o.frame != null) allFrames.add(o.frame);
const nFrames = allFrames.size;

// --- Mark stuck based on unique-frame count per bin ---
let stuckCount = 0;
for (const o of objs) {
  const fs = binFrames[o._bin];
  const run = fs ? fs.size : 0;
  o.stuckRun = run;
  if (run >= MIN_STUCK_FRAMES) {
    o.stuck = true;
    stuckCount++;
  }
}

// --- Thumbnails: prefer stuck ones, then fill with a spaced sample of the rest ---
const stuckObjs = objs.filter(o => o.stuck);
const transientObjs = objs.filter(o => !o.stuck);

const pickThumbs = [];
// All stuck (up to MAX_THUMBS), then transients
for (const o of stuckObjs) {
  if (pickThumbs.length >= MAX_THUMBS) break;
  pickThumbs.push(o);
}
if (pickThumbs.length < MAX_THUMBS && transientObjs.length) {
  const remaining = MAX_THUMBS - pickThumbs.length;
  const step = Math.max(1, transientObjs.length / remaining);
  for (let k = 0; k < remaining && k * step < transientObjs.length; k++) {
    pickThumbs.push(transientObjs[Math.floor(k * step)]);
  }
}

const dir = msg.tsvDir
  ? (OBJ_ROOT + String(msg.tsvDir).replace(/^\/+/, "").replace(/\/+$/, ""))
  : null;

let ok = 0, miss = 0, firstErr = null;
if (dir) {
  for (const o of pickThumbs) {
    if (!o.file) { miss++; continue; }
    try {
      const buf = fs.readFileSync(dir + "/" + o.file);
      o.thumb = "data:image/jpeg;base64," + buf.toString("base64");
      ok++;
    } catch (e) {
      miss++;
      if (!firstErr) firstErr = e.message;
    }
  }
  node.warn("Audit thumbs: " + ok + " ok, " + miss + " missing" + (firstErr ? " firstErr=" + firstErr : ""));
} else {
  node.warn("Audit thumbs: msg.tsvDir not set");
}

// --- Summary stats ---
const blurVals = objs.map(o => o.blur).filter(v => Number.isFinite(v)).sort((a, b) => a - b);
const esdVals  = objs.map(o => o.esd ).filter(v => Number.isFinite(v)).sort((a, b) => a - b);
const q = (arr, p) => arr.length ? arr[Math.floor(arr.length * p)] : 0;

const summary = {
  totalObjects: objs.length,
  nFrames,
  stuckCount,
  stuckPct: objs.length ? (stuckCount / objs.length) * 100 : 0,
  medianBlur: q(blurVals, 0.5),
  medianESD:  q(esdVals, 0.5),
  p10Blur: q(blurVals, 0.1),
  p90Blur: q(blurVals, 0.9),
  sharpPct:  blurVals.length ? 100 * blurVals.filter(v => v >= 120).length / blurVals.length : 0,
  blurryPct: blurVals.length ? 100 * blurVals.filter(v => v <  60).length / blurVals.length : 0,
  binPx: BIN_PX,
  minStuckFrames: MIN_STUCK_FRAMES
};

// strip internal fields before emit
for (const o of objs) { delete o._bin; }

let stuckMap = null;
let flatColor = null;
if (msg.tsvDir) {
  const cleanDir = CLEAN_ROOT + String(msg.tsvDir).replace(/^\/+/, "").replace(/\/+$/, "");
  try {
    const buf = fs.readFileSync(cleanDir + "/stuck_map.jpg");
    stuckMap = "data:image/jpeg;base64," + buf.toString("base64");
  } catch (e) {
    node.warn("Audit: no stuck_map.jpg (" + e.code + ") at " + cleanDir);
  }
  try {
    const buf = fs.readFileSync(cleanDir + "/flat_color.jpg");
    flatColor = "data:image/jpeg;base64," + buf.toString("base64");
  } catch (e) {
    node.warn("Audit: no flat_color.jpg (" + e.code + ") at " + cleanDir);
  }
}

msg.payload = { meta, summary, objects: objs, stuckMap, flatColor, tsvDir: msg.tsvDir || null };
return msg;

// Find the TSV file in the directory.
// Cloned from visualizer's "Get tsv path" (63121349).
if (msg.payload.path) {

    const currentPath = msg.payload.path;
    const cleanPath = currentPath.endsWith('/') ? currentPath.slice(0, -1) : currentPath;

    const objRoot = "/home/pi/data/objects/";
    msg.tsvDir = cleanPath.startsWith(objRoot) ? cleanPath.slice(objRoot.length) : cleanPath;

    try {
        const files = fs.readdirSync(cleanPath);
